        return mascotas.get(nombre);  // null si no existe
    }

    public void mostrarEspecies() {
        System.out.println("Especies: " + especies);
    }

    public void mostrarTodasLasMascotas() {
        for (Map.Entry<String, Mascota> e : mascotas.entrySet()) {
            System.out.println(e.getKey() + " -> " + e.getValue());
        }
    }
}

